import{_ as i,c as a,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"平台與整合：多模型 AI 設定 | oh-my-opencode","description":"學習設定和管理多個 AI 平台（Anthropic、OpenAI、Google、Copilot），掌握自動降級機制和智慧模型選擇。","frontmatter":{"title":"平台與整合：多模型 AI 設定 | oh-my-opencode","sidebarTitle":"連接你的 AI 帳號","subtitle":"平台與整合：多模型 AI 設定","description":"學習設定和管理多個 AI 平台（Anthropic、OpenAI、Google、Copilot），掌握自動降級機制和智慧模型選擇。","order":40},"headers":[],"relativePath":"zh-tw/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"zh-tw/code-yeongyu/oh-my-opencode/platforms/index.md"}'),r={name:"zh-tw/code-yeongyu/oh-my-opencode/platforms/index.md"};function s(t,e,n,d,p,h){return o(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="平台與整合" tabindex="-1">平台與整合 <a class="header-anchor" href="#平台與整合" aria-label="Permalink to &quot;平台與整合&quot;">​</a></h1><p>本章節介紹如何設定和管理多個 AI Provider（Anthropic、OpenAI、Google、GitHub Copilot 等），以及 oh-my-opencode 的多模型自動降級機制。</p><p>透過學習本章節，你將掌握如何讓系統根據任務類型和可用模型，智慧選擇最適合的 AI 模型，建構高效、可靠的多模型編排工作流程。</p><h2 id="本章節包含" tabindex="-1">本章節包含 <a class="header-anchor" href="#本章節包含" aria-label="Permalink to &quot;本章節包含&quot;">​</a></h2><p>本章節分為兩部分：</p><h3 id="_1-provider-設定" tabindex="-1">1. <a href="./provider-setup/">Provider 設定</a> <a class="header-anchor" href="#_1-provider-設定" aria-label="Permalink to &quot;1. [Provider 設定](provider-setup/)&quot;">​</a></h3><p>學習如何設定多種 AI Provider，包括：</p><ul><li>Anthropic Claude（主編排器首選）</li><li>OpenAI ChatGPT（架構審查專用）</li><li>Google Gemini（前端和媒體分析）</li><li>GitHub Copilot（備用 Provider）</li><li>Z.ai Coding Plan 和 OpenCode Zen（選用服務）</li></ul><p><strong>學完你能做什麼</strong>：</p><ul><li>✅ 設定 6 種主流 AI Provider</li><li>✅ 使用互動式安裝程式快速設定</li><li>✅ 為不同代理指定最適合的模型</li><li>✅ 使用 <code>doctor</code> 指令診斷設定問題</li></ul><p><strong>預計時間</strong>：25-30 分鐘</p><h3 id="_2-多模型策略" tabindex="-1">2. <a href="./model-resolution/">多模型策略</a> <a class="header-anchor" href="#_2-多模型策略" aria-label="Permalink to &quot;2. [多模型策略](model-resolution/)&quot;">​</a></h3><p>深入理解模型解析系統的三步優先級機制：</p><ul><li>使用者覆蓋（精確控制）</li><li>Provider 降級（自動容錯）</li><li>系統預設（兜底方案）</li></ul><p><strong>學完你能做什麼</strong>：</p><ul><li>✅ 理解模型解析的完整工作流程</li><li>✅ 根據任務需求手動指定模型</li><li>✅ 利用 Provider 降級提高系統強健性</li><li>✅ 診斷和解決模型解析問題</li></ul><p><strong>預計時間</strong>：30-35 分鐘</p><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><p>我們建議按以下順序學習本章節：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[安裝設定完成] --&gt; B[Provider 設定]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[多模型策略]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[進階功能]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>為什麼這個順序？</strong></p><ol><li><strong>先設定，再理解</strong>：先學會如何設定各個 Provider，再理解背後的解析機制</li><li><strong>從簡單到複雜</strong>：Provider 設定是基礎操作，多模型策略是進階概念</li><li><strong>實作驗證理論</strong>：設定完 Provider 後，可以用 <code>doctor</code> 指令驗證多模型策略的效果</li></ol><div class="tip custom-block"><p class="custom-block-title">快速入門路徑</p><p>如果你只想快速上手，可以先完成 <a href="./provider-setup/">Provider 設定</a> 的第 1-4 步（設定基礎 Provider），其他內容可以後續按需學習。</p></div><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>在學習本章節之前，請確保：</p><ul><li>✅ 已完成 <a href="./../installation/">安裝和初始設定</a></li><li>✅ 安裝了 OpenCode（版本 &gt;= 1.0.150）</li><li>✅ 了解基本的 JSON/JSONC 設定檔格式</li><li>✅ 擁有至少一個 AI Provider 的帳號訂閱（推薦 Anthropic Claude）</li></ul><div class="warning custom-block"><p class="custom-block-title">如果沒有 Provider 帳號怎麼辦？</p><p>你可以先學習設定步驟，但不實際連接 Provider。系統會使用 OpenCode 的預設模型作為兜底。</p></div><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><details><summary><strong>我需要設定所有 Provider 嗎？</strong></summary><p>不需要。你可以只設定你最常用的 Provider（比如只設定 Anthropic Claude）。oh-my-opencode 的 Provider 降級機制會自動使用可用的 Provider。</p><p>但如果你想充分利用多模型編排的優勢，建議至少設定 2-3 個 Provider，這樣系統可以根據任務類型自動選擇最適合的模型。</p></details><details><summary><strong>Provider 設定和模型解析有什麼區別？</strong></summary><ul><li><strong>Provider 設定</strong>：是「安裝步驟」，告訴系統你有哪些 AI 服務可用</li><li><strong>模型解析</strong>：是「決策邏輯」，系統如何為每個代理選擇使用哪個 Provider</li></ul><p>比喻：Provider 設定是「招募團隊成員」，模型解析是「分配任務」。</p></details><details><summary><strong>我可以隨時修改設定嗎？</strong></summary><p>可以隨時修改設定檔：</p><ul><li>使用者設定：<code>~/.config/opencode/oh-my-opencode.json</code></li><li>專案設定：<code>.opencode/oh-my-opencode.json</code></li></ul><p>修改後無需重啟，下次使用代理時自動生效。如果修改了 Provider 認證，需要執行 <code>opencode auth login</code> 重新認證。</p></details><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章節後，你可以：</p><h3 id="推薦路徑-學習-ai-代理團隊" tabindex="-1">推薦路徑：學習 AI 代理團隊 <a class="header-anchor" href="#推薦路徑-學習-ai-代理團隊" aria-label="Permalink to &quot;推薦路徑：學習 AI 代理團隊&quot;">​</a></h3><p>繼續學習 <a href="./../../advanced/ai-agents-overview/">AI 代理團隊：10 位專家介紹</a>，了解如何使用不同的代理完成專業任務。</p><h3 id="進階路徑-深度客製化設定" tabindex="-1">進階路徑：深度客製化設定 <a class="header-anchor" href="#進階路徑-深度客製化設定" aria-label="Permalink to &quot;進階路徑：深度客製化設定&quot;">​</a></h3><p>如果你已經熟悉基礎設定，可以跳到 <a href="./../../advanced/advanced-configuration/">設定深度客製化：代理與權限管理</a>，學習：</p><ul><li>如何自訂代理的提示詞</li><li>如何設定代理的權限和存取範圍</li><li>如何建立自訂的代理和 Category</li></ul><h3 id="實戰路徑-使用-prometheus-規劃" tabindex="-1">實戰路徑：使用 Prometheus 規劃 <a class="header-anchor" href="#實戰路徑-使用-prometheus-規劃" aria-label="Permalink to &quot;實戰路徑：使用 Prometheus 規劃&quot;">​</a></h3><p>開始使用 <a href="./../../advanced/prometheus-planning/">Prometheus 規劃：面試式需求收集</a>，透過實際的代理協作體驗多模型編排的威力。</p><hr><p><strong>開始學習</strong>：從 <a href="./provider-setup/">Provider 設定</a> 開始你的多模型編排之旅吧！</p>`,42)])])}const m=i(r,[["render",s]]);export{u as __pageData,m as default};
